const receiveReply = $('Receive Reply').item.json;
const payload = receiveReply.body.payload;
const phoneNumber = payload.sender.contact.identifierValue;
const channelId = payload.channelId;
const contactId = payload.sender.contact.id;
const messageType = payload.body.type;
const messageText = payload.body?.text?.text ||
                    payload.body?.image?.text ||
                    payload.body?.caption ||
                    `[${messageType} message]`;
const now = new Date().toISOString();

const newMessage = { type: messageType, text: messageText, timestamp: now };

const getResponse = $input.item.json;
const existingRow = Array.isArray(getResponse) && getResponse.length > 0 ? getResponse[0] : null;
const existingMessages = existingRow?.messages || [];

const mergedMessages = [...existingMessages, newMessage];

return [{
  json: {
    phone_number: phoneNumber,
    messages: mergedMessages,
    channel_id: channelId,
    contact_id: contactId,
    message_type: messageType,
    updated_at: now
  }
}];

const response = $input.item.json;
const row = Array.isArray(response) ? response[0] : response;

if (!row || !row.messages || row.messages.length === 0) {
  return [{
    json: {
      phone_number: $('Store myTs').item.json.phone_number,
      merged_text: '',
      message_type: $('Store myTs').item.json.message_type || 'text',
      message_count: 0
    }
  }];
}

const messages = row.messages;
const textParts = messages
  .map(m => (m.text && !m.text.startsWith('[')) ? m.text : null)
  .filter(Boolean);

const merged_text = textParts.join('\n');

// Determine dominant message type by priority (non-text types take precedence)
const typePriority = ['image', 'file', 'voice', 'audio', 'video', 'link_preview', 'text'];
const foundTypes = new Set(messages.map(m => m.type));
const message_type = typePriority.find(t => foundTypes.has(t)) || 'text';

return [{
  json: {
    phone_number: row.phone_number,
    channel_id: row.channel_id,
    contact_id: row.contact_id,
    merged_text,
    message_type,
    message_count: messages.length
  }
}];

