// Extract the main payload
const payload = $('Receive Reply').item.json.body.payload;
const imageBody = payload?.body?.image?.images;
const imagesFound = [];

if (imageBody && Array.isArray(imageBody)) {
  for (const img of imageBody) {
    if (img.mediaUrl) {
      // Extract Media ID from the end of the URL
      const mediaId = img.mediaUrl.split('/').pop();

      imagesFound.push({
        messageId: payload.id, 
        mediaFileId: mediaId,
        imageUrl: img.mediaUrl,
        caption: payload.body?.image?.text || payload.body?.caption || "",
        senderNumber: payload.sender?.contact?.identifierValue || "",
        sender: payload.sender?.contact?.annotations?.name || "Unknown"
      });
    }
  }
}

// Return the extracted data or a fallback if no images exist
return imagesFound.length > 0 ? imagesFound : [{ imageUrl: null, status: "no image found" }];

const items = $input.all();
const output = [];

// Get processed message data from earlier in the flow
const processedMessage = $('Get User\'s Message').item.json;
const messageType = processedMessage.message_type;
const messageText = processedMessage.message_text;
const messageCaption = processedMessage.message_caption;

// Build the processed body for image messages
let processedImageBody = null;
if (messageType === 'image' && messageText) {
  processedImageBody = messageText;
  if (messageCaption) {
    processedImageBody += `\n\nCaption: "${messageCaption}"`;
  }
}

items.forEach(item => {
  const messages = item.json.results || [];
  if (messages.length === 0) return;

  const sortedMessages = [...messages].sort((a, b) =>
    new Date(b.createdAt) - new Date(a.createdAt)
  );

  let conversationThread = [];
  let latestLeadMessage = "";
  let lastProspectTime = null;
  let firstSdrReplyTime = null;
  let prospectMessages = [];
  let isFirstProspectMessage = true;

  sortedMessages.forEach(msg => {
    const isProspect = msg.sender.type === 'contact';
    const isUser = msg.sender.type === 'user';
    const roleLabel = isProspect ? 'Prospect' : 'SDR';

    const msgDate = new Date(msg.createdAt);
    const dateStr = msgDate.toLocaleString('en-SG', {
      timeZone: 'Asia/Singapore',
      day: 'numeric',
      month: 'short'
    }) + ' ' + msgDate.toLocaleString('en-SG', {
      timeZone: 'Asia/Singapore',
      hour: '2-digit',
      minute: '2-digit',
      hour12: false
    });

    // Default body from raw message
    let body = msg.body?.text?.text || "[Media/Other]";

    // For the most recent prospect message, substitute processed image data if available
    if (isProspect && isFirstProspectMessage && processedImageBody) {
      body = processedImageBody;
    }

    if (conversationThread.length < 10) {
      conversationThread.push(`[${dateStr}] ${roleLabel}: ${body}`);
    }

    if (isProspect) {
      if (!latestLeadMessage) latestLeadMessage = body;
      lastProspectTime = msgDate;
      prospectMessages.push({ dateStr, body, msgDate });
      isFirstProspectMessage = false;
    } else if (isUser) {
      firstSdrReplyTime = msgDate;
    }
  });

  let latestMessages = "";
  if (prospectMessages.length > 0) {
    const mostRecentProspectTime = prospectMessages[0].msgDate;
    const threeMinutesMs = 3 * 60 * 1000;
    latestMessages = prospectMessages
      .filter(m => Math.abs(mostRecentProspectTime - m.msgDate) <= threeMinutesMs)
      .map(m => `[${m.dateStr}] ${m.body}`)
      .reverse()
      .join('\n\n');
  }

  let responseTimeMinutes = 0;
  if (lastProspectTime && firstSdrReplyTime) {
    const diffMs = Math.abs(firstSdrReplyTime - lastProspectTime);
    responseTimeMinutes = Math.round(diffMs / 60000);
  }

  output.push({
    json: {
      leadMessage: latestLeadMessage,
      conversationId: sortedMessages[0].conversationId,
      conversationThreadFormatted: conversationThread.reverse().join('\n\n'),
      latestMessages: latestMessages,
      responseTimeMinutes: responseTimeMinutes,
      summary: {
        totalMessages: sortedMessages.length,
        latestRole: sortedMessages[0].sender.type === 'contact' ? 'Prospect' : 'SDR'
      }
    }
  });
});

return output;

